#include <stdio.h>
#include <stdlib.h>

#define NUM_NUMBERS 5

int main(void) {
    int numbers[NUM_NUMBERS];
    int guessedPositions[NUM_NUMBERS] = {0};
    int score = 0;

    // Generate 5 unique random numbers between 1 and 10
    for (int i = 0; i < NUM_NUMBERS; i++) {
        do {
            numbers[i] = rand() % 10 + 1;
        } while (i > 0 && numbers[i] == numbers[i - 1]);
    }

    // Hide the numbers initially
    for (int i = 0; i < NUM_NUMBERS; i++) {
        printf("* ");
    }
    printf("\n");

    // Game loop
    for (int i = 0; i < NUM_NUMBERS; i++) {
        int position;
        char guess[2];

        // Player picks position
        printf("Pick a number between 1 and %d: ", NUM_NUMBERS);
        scanf("%d", &position);

        // Player guesses even or odd
        printf("Guess if the number at position %d is 'E'ven or 'O'dd: ", position);
        scanf("%s", guess);

        // Calculate correctness
        if (guess[0] == 'E') {
            guessedPositions[position - 1] = numbers[position - 1] % 2 == 0;
        } else if (guess[0] == 'O') {
            guessedPositions[position - 1] = numbers[position - 1] % 2 != 0;
        }

        // Reveal the number
        printf("Number at position %d: ", position);
        if (guessedPositions[position - 1]) {
            printf("%d\n", numbers[position - 1]);
            score += 5;
        } else {
            printf("*\n");
        }
    }

    // Display final score
    printf("Final Score: %d\n", score);

    return 0;
}
